const row = $input.first().json;
const rawPhone = row.phone || row.Phone || row.phone_number || '';

// Normalize phone number
let phone = rawPhone.replace(/[^0-9+]/g, '');
if (phone.length === 10) phone = '+1' + phone;
if (phone.length === 11 && !phone.startsWith('+')) phone = '+' + phone;

const isValid = /^\+1[2-9][0-9]{9}$/.test(phone) || /^\+[1-9][0-9]{10,14}$/.test(phone);

return [{
  json: {
    ...row,
    phone_normalized: phone,
    phone_valid: isValid,
    name: row.name || row.Name || row.first_name || 'there',
    email: row.email || row.Email || ''
  }
}];

const fs = require('fs');
const QUEUE_PATH = '/root/.openclaw/workspace/assets/call-queue.json';

let queue = [];
try { queue = JSON.parse(fs.readFileSync(QUEUE_PATH, 'utf8')); } catch(e) { queue = []; }

const phone = $input.first().json.phone_normalized;
const alreadyCalled = queue.some(c => c.phone === phone && c.status !== 'pending');

return [{
  json: {
    ...$input.first().json,
    already_called: alreadyCalled
  }
}];

const fs = require('fs');
const QUEUE_PATH = '/root/.openclaw/workspace/assets/call-queue.json';

let queue = [];
try { queue = JSON.parse(fs.readFileSync(QUEUE_PATH, 'utf8')); } catch(e) { queue = []; }

const lead = $('IF Not Already Called').first().json;
const vapiResponse = $input.first().json;

queue.push({
  call_id: vapiResponse.id,
  phone: lead.phone_normalized,
  name: lead.name,
  email: lead.email,
  status: 'initiated',
  initiated_at: new Date().toISOString(),
  source: 'google_sheets'
});

fs.writeFileSync(QUEUE_PATH, JSON.stringify(queue, null, 2));
return [{ json: { call_id: vapiResponse.id, logged: true } }];
